import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { Home } from 'lucide-react';

const RoomListing = ({ room }) => {
  return (
    <div className="bg-zinc-800 hover:bg-zinc-700 transition duration-300 rounded-xl shadow-2xl p-4 md:p-6 lg:p-8">
      <h2 className="text-indigo-400 text-lg md:text-xl lg:text-2xl font-bold mb-2">{room.name}</h2>
      <p className="text-zinc-300 text-sm md:text-md lg:text-lg mb-4">{room.description}</p>
      <div className="flex justify-between items-center mb-4">
        <span className="text-indigo-400 text-lg md:text-xl lg:text-2xl font-bold">${room.price}</span>
        <Link to={`/rooms/${room.id}`} className="bg-indigo-600 hover:bg-indigo-700 transition duration-300 text-zinc-100 py-2 px-4 rounded-xl">Book Now</Link>
      </div>
      <div className="flex justify-between items-center">
        <span className="text-zinc-300 text-sm md:text-md lg:text-lg">Guests: {room.guests}</span>
        <span className="text-zinc-300 text-sm md:text-md lg:text-lg">Beds: {room.beds}</span>
        <span className="text-zinc-300 text-sm md:text-md lg:text-lg">Bathrooms: {room.bathrooms}</span>
      </div>
    </div>
  );
};

const rooms = [
  { id: 1, name: 'Luxury Suite', description: 'Our luxury suite features a private balcony with stunning views of the city.', price: 500, guests: 2, beds: 1, bathrooms: 1 },
  { id: 2, name: 'Deluxe Room', description: 'Our deluxe room features a comfortable king-size bed and a spacious bathroom.', price: 300, guests: 2, beds: 1, bathrooms: 1 },
  { id: 3, name: 'Standard Room', description: 'Our standard room features a comfortable queen-size bed and a cozy bathroom.', price: 200, guests: 2, beds: 1, bathrooms: 1 },
];

const RoomListings = () => {
  const [filter, setFilter] = useState('');
  const filteredRooms = rooms.filter(room => room.name.toLowerCase().includes(filter.toLowerCase()));

  return (
    <div className="max-w-7xl mx-auto p-4 md:p-6 lg:p-8 pt-6 md:pt-12 lg:pt-16">
      <h1 className="text-indigo-400 text-2xl md:text-3xl lg:text-4xl font-bold mb-4">Room Listings</h1>
      <input type="search" value={filter} onChange={(e) => setFilter(e.target.value)} placeholder="Search rooms" className="w-full p-2 pl-10 text-sm text-zinc-300 bg-zinc-800 border border-zinc-800 rounded-xl focus:outline-none focus:ring-indigo-600 focus:border-indigo-600" />
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 mt-4">
        {filteredRooms.map(room => (
          <RoomListing key={room.id} room={room} />
        ))}
      </div>
    </div>
  );
};

export default RoomListings;

